var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"흐아암......","JPN":"ふわぁ～。","ENG":"*Yawn*...","TWN":"哈啊啊……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아, 해가 떠 있을 때 돌아다니는 건 정말 나랑 안 맞는 것 같아......","JPN":"あぁ、日が昇ってる内に外にいるとか、アタシには不向きね……","ENG":"This day job really doesn't work well for me.","TWN":"啊，我是真的不適合在陽光下閒晃啊……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래도 본국으로 돌아가기 전에 상점가는 둘러봐야겠지?","JPN":"でも、本国に戻る前に電気街には行かないとね！","ENG":"Still, I'd better go check out the local electronics district before I go back home.","TWN":"但回國前總得逛個商店街對吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"유명한 전자상가라고 하니까 쓸만한 것들이 하나쯤은 있을 거야.","JPN":"有名な電気街らしいから、使えそうなもの一つくらいあるでしょ。","ENG":"I heard it's a pretty famous market, so they should have some stuff I could use.","TWN":"聽說這裡是很有名的電子商街，應該會有什麼好東西。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"네 성능을 업그레이드 할 수 있는 좋은 기회라고. 안 그래, 리프노드?","JPN":"リーフノードの性能をアップグレードできるいいチャンスね！","ENG":"This is a great opportunity to get you some upgrades. Wouldn't you agree, Leaf Node?","TWN":"這是提升你性能的好機會，對吧，節點？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>긍정. 긍정. YEAH.</color>","JPN":"<color=#ffd34c>ポジティブ、ポジティブ、YEAH</color>","ENG":"<color=#ffd34c>Affirmative. Affirmative. YEAH.</color>","TWN":"<color=#ffd34c>肯定。肯定。YEAH.</color>"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"거기 핑크머리 아가씨! 이면세계에서 구해 온 특별한 부품에 관심 없으신가요?!!","JPN":"そこのピンク頭のお嬢さん！　裏世界から仕入れた特別な部品はどうですか！？","ENG":"Hey there, young lady with the pink hair! Can I interest you in a special component salvaged from the Counterside?","TWN":"那邊粉色頭髮的小姐！您對異界的特殊商品有沒有興趣？！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"좋은 물건을 찾고 계시는군요! 아, 그런데 얼마까지 알아 보고 오셨어요?","JPN":"何をお探しですか？　ところで、予算はどのくらいで？","ENG":"That's quite an item you're looking for! By the way, did you have any price range in mind?","TWN":"您原來在找好東西啊！啊，不過不知道您到這邊來之前做過多少瞭解？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"찾으시는 물건 대신 이건 어떠신가요! 거의 비슷한 것 같은데......","JPN":"お探しの物の代わりに、こちらはいかがですか？　こちらもすごくいいですよ！","ENG":"How about this instead? It seems pretty close to what you're looking for...","TWN":"雖然沒有您在找的東西，不過這個商品怎麼樣呢！好像差不多……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하아...... 하아......","JPN":"はあ……はあ……","ENG":"*Huff*... *Huff*...","TWN":"哈啊……哈啊……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"더럽게 끈질기네. 대체 몇 번을 붙잡힌 거야......","JPN":"しつこいわね。一体何回引き止めるわけ？","ENG":"Dang, they're persistent. How many times did they get to me?","TWN":"真纏人。我到底還要被叫住幾次阿"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어디 보자. 아까 봐 둔 가게가......","JPN":"どれどれ、さっき検索しておいたお店が……","ENG":"Let's see... Where's that store I saw earlier again?","TWN":"讓我看看……剛才那家店……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"어서 옵쇼. 뭘 찾으십니까?","JPN":"いらっしゃいませ。何をお探しですか？","ENG":"Welcome. What are you looking for?","TWN":"歡迎光臨。您在找什麼呢？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"여기 알파트릭스에서 만든 드론용 비행 장치가 있다던데요.","JPN":"ここアルファトリックスで作ったドローン用の飛行装置があると聞いたんですけど。","ENG":"I heard you've got an Alphatrix flight device for drones here.","TWN":"我聽說這裡有在阿爾法崔克斯製造的無人機設備。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"소형 이터니움 부상장치 말씀이시죠?","JPN":"小型エタニウム浮上装置のことでしょうか？","ENG":"Ah, you mean the small Eternium levitation device?","TWN":"您是說小型永恆之金躍出設備嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"잠깐만 기다리고 계세요. 금방 꺼내 드리겠습니다.","JPN":"少々お待ちください。すぐにお持ちします。","ENG":"Please wait just a moment. I'll bring it out on no time.","TWN":"請稍等，我立刻幫您拿。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하드웨어 업그레이드는 오랜만이네.","JPN":"ハードウェアアップグレードは久々ね。","ENG":"It's been a while since we've done a hardware upgrade.","TWN":"硬體好久沒升級了啊。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"후훗, 티 안 나게 하나씩 바꾸면 언젠가 카일 녀석이 심어 둔 백도어도 안 먹히겠지.","JPN":"ふふっ、目立たないように一つずつ変えて行けば、カイルが設置したバックドアも通じないはずよ。","ENG":"Heh, I bet one day Kyle's backdoor won't even work if I keep changing things bit by bit so he won't notice.","TWN":"呵呵，只要偷偷的換掉一個，凱爾那傢伙安裝的軟體後門肯定也會失效。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그 꼰대 녀석, 비장의 카드가 무력화되면 어떤 표정을 지으려나?","JPN":"あの年寄りみたいなやつの切り札が使えなくなったら、どんな顔をするかしら？","ENG":"I can't wait to see the look on his face when I neutralize his secret weapon against me!","TWN":"不知道那老古板在發現自己失去底牌時會是什麼表情呢?"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEAFNOD_VOICE_NULL_NULL","text":{"KOREA":"<color=#ffd34c>WOO-YEAH.</color>","JPN":"<color=#ffd34c>WOO-YEAH</color>","ENG":"<color=#ffd34c>WOO-YEAH.</color>","TWN":"<color=#ffd34c>WOO-YEAH.</color>"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_QB","text":{"KOREA":"이봐! 점장! 가게에 있나?!","JPN":"おい、店長！　いるか！？","ENG":"Hey! Shopkeep! You here?","TWN":"喂！店長！你在店裡嗎？！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어? 이 목소리는......?","JPN":"うん？　この声は……","ENG":"Huh? That voice...","TWN":"哦？這聲音是……？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"소문 다 들었다고!","JPN":"噂は聞いたぞ！","ENG":"I heard the word on the street!","TWN":"傳聞我都聽說了！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"운 좋게 알파트릭스의 신형 비행장치를 입수했다고 하던데?","JPN":"運良くアルファトリックスの新型飛行装置を手に入れたらしいな？","ENG":"They say you somehow got your hands on the new flight gear from Alphatrix! You lucky dog!","TWN":"聽說你很幸運地入手了阿爾法崔克斯的新型飛行設備？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아직 가지고 있겠지? 괜찮다면 내가 구입하고 싶군.","JPN":"まだ持ってるだろ？　俺が買う。","ENG":"You've still got it, don't you? if it's alright, I'd like to buy it from you.","TWN":"它現在還在你那裡吧？如果可以的話，我想把它買下來。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"이를 어쩌나. 저기 있는 아가씨가 먼저 얘기를 꺼냈거든요.","JPN":"それは困りましたね。こちらのお客さんが先でして。","ENG":"Oh dear. That lady over there asked for it first.","TWN":"這可怎麼辦啊。那邊的小姐已經先說要買這個了。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아가씨? 누군지 몰라도 그건 초보자가 쓸 물건이 아니야.","JPN":"嬢ちゃん。誰かは知らないが、それは初心者が扱うような代物じゃない。","ENG":"Young lady? Whoever you are, this thing is not for beginners.","TWN":"小姐？雖然不知道是誰，但那絕對不是新手可以駕馭的東西。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"괜히 다루지도 못할 물건을 사서 후회하지 말고 내게 양보하는 게......","JPN":"ちゃんと扱えないような物を買って後悔する前に俺に譲れ……","ENG":"You'll just regret buying something you can't even manage. Why don't you just let me—","TWN":"與其買到無法駕馭的東西而後悔，不如讓給我……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"헬로, 아저씨.","JPN":"ハーイ、おじさん。","ENG":"Hey there, Mister.","TWN":"嗨，大叔。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"히끅!","JPN":"うっ！","ENG":"Eeep!","TWN":"咿呀！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"오랜만이야, 두뇌파 용병 존 메이슨!","JPN":"久しぶり、頭脳派傭兵のジョン・メイソン！","ENG":"Long time no see, John \\"the Intelligent Mercenary\\" Mason!","TWN":"好久不見，頭腦派傭兵約翰·梅森！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그런데 안색이 좀 나빠 보이는걸?","JPN":"ところで、顔色悪いけどどうかしたの？","ENG":"You don't look well for some reason.","TWN":"不過你的臉色看起來不太好啊？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......너 때문이야, 너.","JPN":"……あんたのせいだ。","ENG":"You know it's because of you.","TWN":"……都是因為妳啊。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아직 본국에 돌아가지 않았나? 왜 지구 반대편에서 다시 마주치는 거야?","JPN":"まだ本国に戻っていなかったのか？　地球の反対側でまた会うとはな。","ENG":"Aren't you supposed to be back home by now? Why am I running into you halfway across the planet?","TWN":"妳還沒回國啊？我們為什麼會在地球的另一端再次見面啊？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그야 이 거리에 오래된 전자 부품 가게가 많다고 해서 구경이나 해볼까 해서 왔지.","JPN":"ここは古い電子機器のお店が多いって聞いたから見に来たのよ。","ENG":"I heard they've got a lot of vintage electronics stores here. Thought I'd come browse a little.","TWN":"啊，因為我聽說這裡有很多販賣舊電子零件的商店，就想來參觀一下。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"물건들이 나쁘진 않은데, 호객이 너무 심하네.","JPN":"品はいいんだけど、客引きがすごくて。","ENG":"They've got some good stuff here, but too much solicitation.","TWN":"東西是不錯，但這裡攬客的攻勢讓我有點招架不住。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐 이 거리가 신참들에겐 좀 거칠긴 하지.","JPN":"まぁ、ここは初めてだと慣れないかもな。","ENG":"Yeah, this neighborhood's not exactly the easiest water to navigate for beginners.","TWN":"這個嘛，這條街確實對新人不太友善。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아무튼 네가 사겠다고 한 부품 말인데, 나한테 넘겨 주면 안될까?","JPN":"とにかく、その部品だが俺に譲ってもらえないか？","ENG":"Anyway, could you possibly let me buy that part that you called dibs on?","TWN":"總之，妳想買的那個零件，能不能讓給我？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"같이 사선을 넘은 전우인데 그 정도는 당연히 가능하겠지?","JPN":"生死を共にした戦友だろう？　それくらいの頼みはできると思うが。","ENG":"Surely that's not asking for too much, since we've been through life and death together, right?","TWN":"我們可是一起並肩作戰過的戰友啊，這種小小的讓步應該可以吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"일 없어요. 훠이, 훠이.","JPN":"お断りよ、ほら、行った行った！","ENG":"Heck no. Shoo, shoo.","TWN":"沒這種事。走開，走開。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"나도 꼭 써야 할 데가 있어서 한참 찾아 다닌 부품이라고.","JPN":"アタシもこれが必要でやっと見つけたの。","ENG":"It took me ages to find it. I really need it, too.","TWN":"我也是必須用到這個零件，到處找了很久。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런가......","JPN":"そうか……","ENG":"I see...","TWN":"是嗎……？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그렇다면 할 수 없지. 오늘은 내가 운이 나쁘군.","JPN":"なら仕方がない。今日はツイてなかったようだ。","ENG":"Oh well, then. I guess it's just not my lucky day.","TWN":"那就沒辦法了，看來今天我的運氣不太好。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럼 쇼핑 잘 하라고. 나중에 본국에서 만나지.","JPN":"それじゃ、また本国で会おう。","ENG":"Have fun shopping. Maybe I'll see you stateside later.","TWN":"那麼祝妳購物愉快吧。之後回國後再見。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래~ 잘 가, 아저씨.","JPN":"うん。バイバイ、おじさん！","ENG":"Sure. Bye, Mister.","TWN":"好喔～掰啦，大叔。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"흐음...... 다른 곳을 가봐야 허탕일 텐데.","JPN":"ふむ……他の場所を探し回ったところで見つからないと思いますが。","ENG":"Hmm... He won't have much luck elsewhere.","TWN":"嗯……他去其他地方應該也買不到吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"이 부품은 이면세계에서 찾은 특별한 재료로 만든 거라 이게 마지막이라고 들었거든요.","JPN":"この部品は裏世界で見つけた特別な材料で作ったもので、これが最後だと聞いています。","ENG":"I heard this was the last of its kind since it was made from special materials found in the Counterside.","TWN":"畢竟這個零件是用異界的特殊材料製作的，所以這是最後一個。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래......?","JPN":"……そうなの？","ENG":"Really?","TWN":"是嗎……？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그런데 저 아저씬 이걸로 뭘 하려고 했던 거야?","JPN":"でも、あのおじさん、これで何しようとしてたのかしら？","ENG":"What was he going to do with it anyway?","TWN":"話說那個大叔想用它做什麼？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"손님과 비슷해요. 개인용 드론이 지난 번 전투로 망가져서 고치는 중이라고 하던데......","JPN":"お客さんと同じですよ。個人用ドローンがこの前の戦闘で壊れてしまい、修理中だそうです。","ENG":"Much like you, ma'am. His personal drone was damaged in combat, so he's been trying to fix it...","TWN":"和您差不多。那位客人的私人無人機似乎在上次戰鬥中壞掉了，現在正在修理……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OWNER_NPC_NULL_NULL","text":{"KOREA":"이름이 이안 주니어였나? 죽은 형의 이름을 딴 물건이라 애착이 큰 것 같아요.","JPN":"確か名前はイアン・ジュニアだったと思います。\\n亡き兄の名前から取ってつけたそうで、愛着があるそうですよ。","ENG":"I think he named it Ian Jr. or something? It was named after his late brother. So I guess he's quite attached to it.","TWN":"無人機的名字好像是小伊恩？因為那是用他去世的兄長名字來命名的，所以他非常戀戀不捨呢。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"나 참...... 괜히 들어 버렸잖아.","JPN":"まったく……聞かなきゃよかったわ。","ENG":"Dang it... I really didn't need to hear that.","TWN":"我也真是……不小心聽了些沒用的東西呢。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"후우...... 결국 부품은 못 구했군......","JPN":"ふぅ……結局見つからなかったな。","ENG":"*Sigh*... Better luck next time, I guess...","TWN":"呼……結果還是沒找到那個零件啊……"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그나저나 내가 없는 동안 별일 없었나?","JPN":"俺がいない間、何か問題はなかったか？","ENG":"Anything happen while I was gone?","TWN":"我不在的時候有發生什麼事嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"사장님~ 택배왔어요.","JPN":"社長、荷物が届いてました。","ENG":"Someone sent you a package, boss.","TWN":"老闆～有快遞喔。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"택배? 올 곳이 없는데...... 누가 보낸 거지?","JPN":"荷物？　どこからだ……差出人は？","ENG":"What package? I wasn't expecting any... Who’s it from?","TWN":"快遞？我應該沒有快遞吧……誰發過來的啊？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"<color=#ffd34c>핑크머리 미녀</color>라고 적혀 있네요.","JPN":"<color=#ffd34c>ピンク髪の美女</color>と書いてありますね。","ENG":"It says it's from the <color=#ffd34c>Pink-haired Beauty</color>.","TWN":"上面寫著<color=#ffd34c>粉色頭髮的美女</color>。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"미인계에 당해서 이상한 물건이라도 산 거 아니에요?","JPN":"色仕掛けに騙されて、何か買ったんですか？","ENG":"Did someone seduce you into buying her stuff?","TWN":"老闆是不是中了美人計，買了些奇怪的東西啊？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그럴 리가...... 애초에 핑크머리 미녀 같은 건 만난 적도 없는데......","JPN":"まさか……そもそもピンク髪の美女など、会ったことがない。","ENG":"Of course not... I never even met any pink-haired beauty...","TWN":"怎麼可能……我從沒見過什麼粉色頭髮的美女啊……"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어라, 이건?","JPN":"おぉ、これは……？","ENG":"Huh? This?","TWN":"咦，這是？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"왜요? 뭐가 들었는데요?","JPN":"どうかしましたか？　何が入っていたんですか？","ENG":"What's wrong? What is it?","TWN":"怎麼了？裡面有什麼東西嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이거...... 아무래도 꼬마 아가씨에게 빚을 지게 된 것 같아.","JPN":"これは……あの嬢ちゃんに借りができたようだな。","ENG":"Well... Looks like I owe the kid a favor now.","TWN":"這……看來我不管怎樣都欠了那個小姐一筆帳呢。"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"ZHANG_MASON_NULL_NULL","text":{"KOREA":"히익! 미성년자는 불법이에요!","JPN":"ひいっ……！　未成年は違法ですよ！","ENG":"Eeek! You could go to jail for that!","TWN":"咿！未成年人是違法的！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런 거 아니라고!","JPN":"そ、そういうんじゃない！","ENG":"It's not what you think!","TWN":"不是那種事！"},"stage":{"bg":"OFFICE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZHANG_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};